// Process framework phase updates
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // Calculate progress based on phase
  const phaseProgress = {
    'initialization': 10,
    'foundation_analysis': 30,
    'deep_investigation': 50,
    'qe_intelligence': 65,
    'ai_analysis': 80,
    'test_generation': 95,
    'cleanup': 100
  };

  const enrichedData = {
    ...data,
    progress_percentage: phaseProgress[data.phase] || 0,
    phase_display: data.phase ? data.phase.replace(/_/g, ' ').toUpperCase() : 'UNKNOWN',
    timestamp_formatted: new Date(data.timestamp).toLocaleTimeString(),
    execution_id: data.run_id || data.jira_ticket
  };

  // Store in static data for dashboard
  const staticData = $getWorkflowStaticData('global');
  if (!staticData.executions) staticData.executions = {};
  if (!staticData.executions[enrichedData.execution_id]) {
    staticData.executions[enrichedData.execution_id] = {
      phases: {},
      agents: {},
      start_time: new Date().toISOString()
    };
  }

  staticData.executions[enrichedData.execution_id].phases[data.phase] = {
    status: data.status,
    timestamp: data.timestamp,
    metrics: data.metrics
  };

  staticData.current_execution = enrichedData.execution_id;
  staticData.last_update = enrichedData;

  results.push({ json: enrichedData });
}

return results;

// Process agent updates
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  const enrichedData = {
    ...data,
    agent_display: data.agent ? data.agent.replace(/_/g, ' ').toUpperCase() : 'UNKNOWN',
    timestamp_formatted: new Date(data.timestamp).toLocaleTimeString(),
    execution_id: data.run_id || data.jira_ticket,
    confidence_display: data.confidence ? `${data.confidence}%` : 'N/A',
    execution_time_display: data.execution_time ? `${data.execution_time}s` : 'N/A'
  };

  // Store in static data
  const staticData = $getWorkflowStaticData('global');
  if (!staticData.executions) staticData.executions = {};
  if (!staticData.executions[enrichedData.execution_id]) {
    staticData.executions[enrichedData.execution_id] = {
      phases: {},
      agents: {},
      start_time: new Date().toISOString()
    };
  }

  staticData.executions[enrichedData.execution_id].agents[data.agent] = {
    status: data.status,
    confidence: data.confidence,
    execution_time: data.execution_time,
    timestamp: data.timestamp,
    findings_summary: data.findings_summary
  };

  staticData.current_execution = enrichedData.execution_id;
  staticData.last_update = enrichedData;

  results.push({ json: enrichedData });
}

return results;

// Generate comprehensive dashboard data
const items = $input.all();
const staticData = $getWorkflowStaticData('global');
const results = [];

// Get current execution data
const currentExecId = staticData.current_execution;
const currentExec = staticData.executions?.[currentExecId] || {};

// Build dashboard data
const dashboardData = {
  execution_id: currentExecId,
  jira_ticket: items[0]?.json?.jira_ticket || 'Unknown',
  timestamp: new Date().toISOString(),

  // Overall progress
  overall_progress: calculateOverallProgress(currentExec),

  // Phase statuses
  phases: {
    initialization: currentExec.phases?.initialization || { status: 'pending' },
    foundation_analysis: currentExec.phases?.foundation_analysis || { status: 'pending' },
    deep_investigation: currentExec.phases?.deep_investigation || { status: 'pending' },
    qe_intelligence: currentExec.phases?.qe_intelligence || { status: 'pending' },
    ai_analysis: currentExec.phases?.ai_analysis || { status: 'pending' },
    test_generation: currentExec.phases?.test_generation || { status: 'pending' },
    cleanup: currentExec.phases?.cleanup || { status: 'pending' }
  },

  // Agent statuses
  agents: {
    agent_a: currentExec.agents?.agent_a || { status: 'inactive' },
    agent_d: currentExec.agents?.agent_d || { status: 'inactive' },
    agent_b: currentExec.agents?.agent_b || { status: 'inactive' },
    agent_c: currentExec.agents?.agent_c || { status: 'inactive' }
  },

  // Metrics
  metrics: {
    total_agents: Object.keys(currentExec.agents || {}).length,
    completed_agents: Object.values(currentExec.agents || {}).filter(a => a.status === 'completed').length,
    average_confidence: calculateAverageConfidence(currentExec.agents),
    total_execution_time: calculateTotalExecutionTime(currentExec)
  },

  // Last update info
  last_update: staticData.last_update || {}
};

function calculateOverallProgress(exec) {
  const phases = exec.phases || {};
  const weights = {
    initialization: 10,
    foundation_analysis: 20,
    deep_investigation: 20,
    qe_intelligence: 10,
    ai_analysis: 20,
    test_generation: 15,
    cleanup: 5
  };

  let progress = 0;
  for (const [phase, weight] of Object.entries(weights)) {
    if (phases[phase]?.status === 'completed') {
      progress += weight;
    } else if (phases[phase]?.status === 'running') {
      progress += weight * 0.5;
    }
  }

  return Math.round(progress);
}

function calculateAverageConfidence(agents) {
  const confidences = Object.values(agents || {}).map(a => a.confidence).filter(c => c);
  if (confidences.length === 0) return 0;
  return Math.round(confidences.reduce((a, b) => a + b, 0) / confidences.length);
}

function calculateTotalExecutionTime(exec) {
  const times = Object.values(exec.agents || {}).map(a => a.execution_time || 0);
  return times.reduce((a, b) => a + b, 0).toFixed(1);
}

results.push({ json: dashboardData });
return results;

// Process error notifications
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // Classify error severity
  const severity = classifyErrorSeverity(data.error_message);

  const errorData = {
    ...data,
    severity,
    should_alert: ['critical', 'high'].includes(severity),
    timestamp_formatted: new Date(data.timestamp).toLocaleTimeString(),
    alert_message: `🚨 *Error Alert - ${severity.toUpperCase()}*\n` +
                   `JIRA: ${data.jira_ticket}\n` +
                   `Phase: ${data.phase || 'Unknown'}\n` +
                   `Agent: ${data.agent || 'Unknown'}\n` +
                   `Error: ${data.error_message}`
  };

  results.push({ json: errorData });
}

function classifyErrorSeverity(message) {
  const msg = (message || '').toLowerCase();
  if (msg.includes('fatal') || msg.includes('crash')) return 'critical';
  if (msg.includes('error') || msg.includes('failed')) return 'high';
  if (msg.includes('warning') || msg.includes('retry')) return 'medium';
  return 'low';
}

return results;
